using System.ComponentModel.DataAnnotations.Schema;using System.Reflection;using System.Text.Json;using JPN = System.Text.Json.Serialization.JsonPropertyNameAttribute;using Smoower.Minified.EFCore;namespace Smoower.Minified.Tests;public class ShortNameTests{private class Row{[Col("RecurrenceDays")] public int? RD { get; set; }}private class Dto{[JPN("recurrenceDays")] public int? RD { get; set; }}[F]public void Col_IsResolvedAsColumnWithLongName(){var attr = typeof(Row).GetProperty(nameof(Row.RD))!.GetCustomAttribute<ColumnAttribute>();attr.notNul();attr!.Name.eq("RecurrenceDays");}[F]public void Jpn_PinsTheWireName()=> JsonSerializer.Serialize(new Dto { RD = 7 }).eq("{\"recurrenceDays\":7}");}
